(function(){
'use strict';
const $=(s,r=document)=>r.querySelector(s); const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
const API='/api/houses';
const state={page:1,pageSize:20,search:'',house_type:'',condition:'',fire_risk:'',located:'',sort:'house_code',direction:'ASC',catalogs:null,selectedHousehold:null,householdSuggestions:[],current:null,structures:[]};
const labels={all:'T\u1ea5t c\u1ea3',choose:'Ch\u1ecdn',unknown:'Ch\u01b0a c\u1eadp nh\u1eadt',noData:'Ch\u01b0a c\u00f3 d\u1eef li\u1ec7u nh\u00e0 \u1edf',loading:'\u0110ang t\u1ea3i...',permission:'T\u00e0i kho\u1ea3n hi\u1ec7n t\u1ea1i kh\u00f4ng c\u00f3 quy\u1ec1n th\u1ef1c hi\u1ec7n thao t\u00e1c n\u00e0y',yes:'C\u00f3',no:'Kh\u00f4ng',view:'Xem',edit:'S\u1eeda',del:'X\u00f3a'};
function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));}
function num(v){return new Intl.NumberFormat('vi-VN').format(Number(v||0));}
function date(v){if(!v)return labels.unknown; const d=new Date(v); return Number.isNaN(d.getTime())?String(v):new Intl.DateTimeFormat('vi-VN').format(d);}
function toast(msg,type='success'){ if(typeof showToast==='function') showToast(msg,type); else console[type==='danger'?'error':'log'](msg); }
function can(module,action){const role=(window.App?.user?.role||'').toUpperCase(); if(['SUPER_ADMIN','ADMIN'].includes(role))return true; if(role==='OFFICER')return module==='houses'&&['read','create','update'].includes(action); if(role==='VIEWER')return module==='houses'&&action==='read'; return true;}
function registerModal(id){const modal=$('#'+id),service=window.Thon09Platform?.modals; if(modal&&service?.registerBootstrap)service.registerBootstrap(id,'#'+id); return modal;}
function openModal(id){if(window.Thon09Platform?.modals?.open){const result=window.Thon09Platform.modals.open(id); if(result)return result;} return window.bootstrap?.Modal?.getOrCreateInstance?.($('#'+id))?.show();}
function closeModal(id){if(window.Thon09Platform?.modals?.close){const result=window.Thon09Platform.modals.close(id); if(result)return result;} return window.bootstrap?.Modal?.getOrCreateInstance?.($('#'+id))?.hide();}
async function request(url,options={}){ if(typeof api==='function')return api(url,options); const token=window.App?.token||localStorage.getItem('thon09_token')||''; const init={method:options.method||'GET',headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''}}; if(options.body instanceof FormData)init.body=options.body; else if(options.body){init.headers['Content-Type']='application/json';init.body=JSON.stringify(options.body);} const res=await fetch(url,init); const json=await res.json().catch(()=>null); if(!res.ok||json?.ok===false)throw new Error(json?.error?.message||'Kh\u00f4ng t\u1ea3i \u0111\u01b0\u1ee3c d\u1eef li\u1ec7u'); return json?.data??json;}
function confirmAction(options){const dialog=window.Thon09Platform?.confirmDialog; if(dialog?.ask)return dialog.ask(options); return Promise.resolve(typeof window.confirm==='function'?window.confirm(options.message||'Xác nhận thao tác?'):false);}
function debounce(fn,ms){let t;return function(){clearTimeout(t);t=setTimeout(()=>fn.apply(this,arguments),ms);};}
document.addEventListener('DOMContentLoaded',init); document.addEventListener('thon09:screen-change',e=>{if(e.detail?.screen==='houses')load();});
function init(){registerModal('houseDetailModal'); registerModal('houseFormModal');
$('#houseForm')?.addEventListener('submit',save); $('#houseHouseholdAutocomplete')?.addEventListener('input',debounce(searchHouseholds,250)); document.addEventListener('pointerdown',e=>{if(!e.target.closest('#houseHouseholdSuggestions')&&e.target.id!=='houseHouseholdAutocomplete')hideSuggestions();});
$('#housesSearch')?.addEventListener('input',debounce(()=>{state.search=$('#housesSearch').value.trim();state.page=1;load();},300)); [['housesTypeFilter','house_type'],['housesConditionFilter','condition'],['housesFireRiskFilter','fire_risk'],['housesLocatedFilter','located']].forEach(([id,key])=>$('#'+id)?.addEventListener('change',e=>{state[key]=e.target.value;state.page=1;load();}));
$('#housesPageSize')?.addEventListener('change',e=>{state.pageSize=Number(e.target.value||20);state.page=1;load();}); registerHousePlatformActions(); extendReports(); if($('#housesScreen')?.classList.contains('active'))load(); }
function registerHousePlatformActions(){const actions=window.Thon09Platform&&window.Thon09Platform.actions; if(!actions||typeof actions.register!=='function')return; actions.register('houses.create',()=>openForm()); actions.register('houses.search',()=>{state.search=$('#housesSearch')?.value.trim()||'';state.page=1;load();}); actions.register('houses.reset',()=>reset()); actions.register('houses.export',context=>exportReport(context.dataset.format||'excel')); actions.register('houses.page',context=>{state.page=Number(context.dataset.page||1);load();}); actions.register('houses.detailEdit',()=>{if(state.current)openForm(state.current.id);}); actions.register('houses.addStructure',()=>addStructureRow()); actions.register('houses.removeStructure',context=>{syncStructureState();state.structures.splice(Number(context.dataset.index||0),1);renderStructureRows();}); actions.register('houses.selectHousehold',context=>selectHousehold(state.householdSuggestions.find(x=>String(x.id)===context.dataset.id))); actions.register('houses.detail',context=>openDetail(Number(context.dataset.id||context.dataset.houseId||0))); actions.register('houses.edit',context=>openForm(Number(context.dataset.id||context.dataset.houseId||0))); actions.register('houses.delete',context=>remove(Number(context.dataset.id||context.dataset.houseId||0))); if(typeof actions.bind==='function')actions.bind(document);}
async function ensureCatalogs(){if(state.catalogs)return state.catalogs; state.catalogs=await request(API+'/catalogs',{cacheTtl:60000}); fill('#housesTypeFilter',state.catalogs.house_types,labels.all); fill('#housesConditionFilter',state.catalogs.conditions,labels.all); fill('#housesFireRiskFilter',state.catalogs.fire_risks,labels.all); fill('#houseTypeSelect',state.catalogs.house_types,labels.choose); fill('#houseStructureSelect',state.catalogs.structure_types,labels.choose); fill('#houseConditionSelect',state.catalogs.conditions,labels.choose); fill('#houseSoliditySelect',state.catalogs.solidities,labels.choose); fill('#houseUsageSelect',state.catalogs.usages,labels.choose); fill('#houseLegalSelect',state.catalogs.legal_statuses,labels.choose); fill('#houseFireRiskSelect',state.catalogs.fire_risks,labels.choose); fill('#housePhotoTypeSelect',state.catalogs.photo_types,labels.choose); return state.catalogs;}
function fill(sel,items,first){const el=$(sel); if(!el)return; el.innerHTML='<option value="">'+esc(first||labels.choose)+'</option>'+(items||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label||i.value)+'</option>').join('');}
function params(){const p=new URLSearchParams({page:state.page,pageSize:state.pageSize,sort:state.sort,direction:state.direction}); ['search','house_type','condition','fire_risk','located'].forEach(k=>{if(state[k])p.set(k,state[k]);}); return p;}
async function load(){if(!can('houses','read'))return; await ensureCatalogs(); try{const data=await request(API+'?'+params().toString(),{cacheTtl:3000}); renderGrid(data); renderPager(data); renderDashboard();}catch(e){toast(e.message,'danger');}}
async function renderDashboard(){const host=$('#housesMiniDashboard'); if(!host)return; try{const d=await request(API+'/dashboard?'+params().toString(),{cacheTtl:8000}); const m=d.metrics||{}; const cards=[['T\u1ed5ng s\u1ed1 nh\u00e0',m.total_houses,'fa-building-user','green'],['Nh\u00e0 ki\u00ean c\u1ed1',m.solid_houses,'fa-house-chimney','blue'],['Nh\u00e0 xu\u1ed1ng c\u1ea5p',m.degraded_houses,'fa-triangle-exclamation','red'],['C\u00f3 camera',m.camera_houses,'fa-video','orange'],['Nguy c\u01a1 PCCC cao',m.high_fire_risk_houses,'fa-fire-extinguisher','red'],['C\u00f4ng tr\u00ecnh ph\u1ee5',m.structure_total,'fa-warehouse','blue']]; host.innerHTML=cards.map(c=>'<article class="houses-kpi-card tone-'+c[3]+'"><span><i class="fa-solid '+c[2]+'"></i></span><div><p>'+esc(c[0])+'</p><strong>'+num(c[1])+'</strong></div></article>').join('');}catch(e){host.innerHTML='';}}
function renderGrid(data){const host=$('#housesGrid'); if(!host)return; const items=data.items||[]; $('#housesTotalCount')&&($('#housesTotalCount').textContent='T\u1ed5ng s\u1ed1: '+num(data.total||0)+' nh\u00e0'); host.innerHTML=items.length?items.map(cardHtml).join(''):'<div class="houses-empty">'+labels.noData+'</div>';}
function cardHtml(r){const id=Number(r.id||0);return '<article class="house-card"><div class="house-card-photo">'+(r.cover_photo_url?'<img src="'+esc(r.cover_photo_url)+'" alt="">':'<i class="fa-solid fa-house-chimney"></i>')+'</div><div class="house-card-body"><div class="house-card-top"><div><span>'+esc(r.house_code)+'</span><h4>'+esc(r.house_name||r.house_type||'Nh\u00e0 \u1edf')+'</h4></div>'+statusBadge(r)+'</div><p><strong>'+esc(r.head_citizen_name||'')+'</strong> · '+esc(r.household_code||'')+'</p><p>'+esc(r.address||r.household_address||labels.unknown)+'</p><div class="house-meta"><span><i class="fa-solid fa-layer-group"></i> '+num(r.floors)+' t\u1ea7ng</span><span><i class="fa-solid fa-ruler-combined"></i> '+num(r.floor_area)+' m\u00b2</span><span><i class="fa-solid fa-warehouse"></i> '+num(r.structure_count)+'</span></div><div class="house-badges"><span>'+esc(r.house_type||labels.unknown)+'</span><span class="fire-'+esc(String(r.fire_risk||'LOW').toLowerCase())+'">PCCC: '+esc(r.fire_risk_label||'')+'</span>'+(r.latitude&&r.longitude?'<span>GPS</span>':'<span>Ch\u01b0a GPS</span>')+'</div><div class="house-actions"><button class="btn btn-sm btn-outline-secondary" type="button" data-platform-action="houses.detail" data-id="'+id+'" title="'+labels.view+'"><i class="fa-solid fa-eye"></i></button>'+(can('houses','update')?'<button class="btn btn-sm btn-outline-primary" type="button" data-platform-action="houses.edit" data-id="'+id+'" title="'+labels.edit+'"><i class="fa-solid fa-pen-to-square"></i></button>':'')+(can('houses','delete')?'<button class="btn btn-sm btn-outline-danger" type="button" data-platform-action="houses.delete" data-id="'+id+'" title="'+labels.del+'"><i class="fa-solid fa-trash"></i></button>':'')+'</div></div></article>';}
function statusBadge(r){return '<span class="house-status '+(r.status==='ACTIVE'?'is-active':'is-muted')+'">'+esc(r.status_label||'')+'</span>';}
function renderPager(data){const host=$('#housesPager'); if(!host)return; const page=Number(data.page||1),totalPages=Number(data.totalPages||1); const pages=[]; for(let i=Math.max(1,page-2);i<=Math.min(totalPages,page+2);i++)pages.push(i); host.innerHTML='<button class="btn btn-sm btn-outline-secondary" '+(page<=1?'disabled':'')+' data-platform-action="houses.page" data-page="'+(page-1)+'">Tr\u01b0\u1edbc</button>'+pages.map(p=>'<button class="btn btn-sm '+(p===page?'btn-primary':'btn-outline-secondary')+'" data-platform-action="houses.page" data-page="'+p+'">'+p+'</button>').join('')+'<button class="btn btn-sm btn-outline-secondary" '+(page>=totalPages?'disabled':'')+' data-platform-action="houses.page" data-page="'+(page+1)+'">Sau</button>';}
async function openDetail(id){try{const r=await request(API+'/'+encodeURIComponent(id),{cacheTtl:0}); state.current=r; $('#houseDetailTitle').textContent=(r.house_code||'')+' - '+(r.house_name||r.house_type||'Nh\u00e0 \u1edf'); $('#houseDetailSubtitle').textContent=(r.household_code||'')+' · '+(r.head_citizen_name||'')+' · '+(r.address||''); $('#houseDetailBody').innerHTML=detailHtml(r); openModal('houseDetailModal');}catch(e){toast(e.message,'danger');}}
function row(label,value){return '<div class="house-info-row"><span>'+esc(label)+'</span><strong>'+esc(value||labels.unknown)+'</strong></div>';}
function bool(v){return v?labels.yes:labels.no;}
function detailHtml(r){return '<div class="house-detail-grid"><section class="house-detail-card"><h4><i class="fa-solid fa-circle-info"></i> Th\u00f4ng tin chung</h4>'+row('Lo\u1ea1i nh\u00e0',r.house_type)+row('K\u1ebft c\u1ea5u',r.structure_type)+row('S\u1ed1 t\u1ea7ng',num(r.floors))+row('Di\u1ec7n t\u00edch \u0111\u1ea5t',num(r.land_area)+' m\u00b2')+row('Di\u1ec7n t\u00edch s\u00e0n',num(r.floor_area)+' m\u00b2')+row('N\u0103m x\u00e2y',r.build_year||'')+row('T\u00ecnh tr\u1ea1ng',r.condition)+row('M\u1ee9c \u0111\u1ed9',r.solidity)+'</section><section class="house-detail-card"><h4><i class="fa-solid fa-plug-circle-bolt"></i> Ti\u1ec7n \u00edch v\u00e0 PCCC</h4>'+row('S\u1ed1 \u0111i\u1ec7n',r.electric_meter)+row('S\u1ed1 n\u01b0\u1edbc',r.water_meter)+row('Internet',bool(r.internet))+row('Camera',bool(r.security_camera))+row('B\u00ecnh ch\u1eefa ch\u00e1y',bool(r.fire_extinguisher))+row('Nguy c\u01a1 PCCC',r.fire_risk_label)+'</section><section class="house-detail-card"><h4><i class="fa-solid fa-scale-balanced"></i> Ph\u00e1p l\u00fd</h4>'+row('Gi\u1ea5y ch\u1ee9ng nh\u1eadn',r.legal_status)+row('M\u1ee5c \u0111\u00edch s\u1eed d\u1ee5ng',r.usage)+row('Ghi ch\u00fa',r.notes)+'</section><section class="house-detail-card"><h4><i class="fa-solid fa-location-dot"></i> GPS</h4>'+row('T\u1ecda \u0111\u1ed9',r.latitude&&r.longitude?(r.latitude+', '+r.longitude):'Ch\u01b0a \u0111\u1ecbnh v\u1ecb')+row('Sai s\u1ed1',r.gps_accuracy?num(r.gps_accuracy)+' m':'')+(r.latitude&&r.longitude?'<a class="btn btn-sm btn-outline-primary mt-2" target="_blank" rel="noopener" href="https://www.openstreetmap.org/?mlat='+encodeURIComponent(r.latitude)+'&mlon='+encodeURIComponent(r.longitude)+'#map=18/'+encodeURIComponent(r.latitude)+'/'+encodeURIComponent(r.longitude)+'"><i class="fa-solid fa-map-location-dot"></i> M\u1edf tr\u00ean GIS</a>':'')+'</section><section class="house-detail-card house-detail-wide"><h4><i class="fa-solid fa-warehouse"></i> C\u00f4ng tr\u00ecnh ph\u1ee5</h4>'+structuresList(r.structures||[])+'</section><section class="house-detail-card house-detail-wide"><h4><i class="fa-solid fa-images"></i> Th\u01b0 vi\u1ec7n \u1ea3nh</h4>'+photoGallery(r.photos||[])+'</section></div>';}
function structuresList(items){if(!items.length)return '<div class="houses-empty compact">Ch\u01b0a c\u00f3 c\u00f4ng tr\u00ecnh ph\u1ee5.</div>'; return '<div class="house-structure-list">'+items.map(s=>'<div><i class="fa-solid fa-check"></i><strong>'+esc(s.structure_type)+'</strong><span>'+esc(s.structure_name||'')+'</span><em>'+num(s.area)+' m\u00b2</em></div>').join('')+'</div>';}
function photoGallery(items){if(!items.length)return '<div class="houses-empty compact">Ch\u01b0a c\u00f3 \u1ea3nh.</div>'; return '<div class="house-photo-gallery">'+items.map(p=>'<a href="'+esc(p.url)+'" target="_blank" rel="noopener"><img src="'+esc(p.url)+'" alt=""><span>'+esc(p.photo_type||'\u1ea2nh')+'</span></a>').join('')+'</div>';}
async function openForm(id=null){if(!can('houses',id?'update':'create'))return toast(labels.permission,'warning'); await ensureCatalogs(); const form=$('#houseForm'); if(!form)return; form.reset(); form.classList.remove('was-validated'); state.structures=[]; renderStructureRows(); form.elements.id.value=''; form.elements.household_id.value=''; $('#houseHouseholdAutocomplete').disabled=!!id; $('#houseHouseholdAutocomplete').value=''; $('#houseHouseholdSelected').textContent=''; hideSuggestions(); if(id){const r=await request(API+'/'+encodeURIComponent(id)); setForm(r);} openModal('houseFormModal');}
function setForm(r){const form=$('#houseForm'); selectHousehold({id:r.household_id,household_code:r.household_code,head_citizen_name:r.head_citizen_name,address:r.household_address||r.address},true); state.structures=(r.structures||[]).map(s=>({structure_type:s.structure_type,structure_name:s.structure_name,area:s.area,build_year:s.build_year,condition:s.condition,notes:s.notes})); renderStructureRows(); Object.entries({id:r.id,household_id:r.household_id,house_name:r.house_name,address:r.address,house_type:r.house_type,structure_type:r.structure_type,floors:r.floors,land_area:r.land_area,building_area:r.building_area,floor_area:r.floor_area,build_year:r.build_year,renovated_year:r.renovated_year,condition:r.condition,solidity:r.solidity,usage:r.usage,legal_status:r.legal_status,electric_meter:r.electric_meter,water_meter:r.water_meter,fire_risk:r.fire_risk,latitude:r.latitude,longitude:r.longitude,gps_accuracy:r.gps_accuracy,notes:r.notes}).forEach(([k,v])=>{const el=form.elements[k]; if(el)el.value=v??'';}); form.elements.internet.checked=!!r.internet; form.elements.security_camera.checked=!!r.security_camera; form.elements.fire_extinguisher.checked=!!r.fire_extinguisher;}
async function save(e){e.preventDefault(); const form=e.currentTarget; if(!form.elements.household_id.value)return toast('Vui l\u00f2ng ch\u1ecdn h\u1ed9 gia \u0111\u00ecnh','warning'); if(!form.checkValidity()){form.classList.add('was-validated');return;} syncStructureState(); const id=form.elements.id.value; const payload=Object.fromEntries(new FormData(form).entries()); payload.internet=form.elements.internet.checked?'1':'0'; payload.security_camera=form.elements.security_camera.checked?'1':'0'; payload.fire_extinguisher=form.elements.fire_extinguisher.checked?'1':'0'; payload.structures=state.structures; delete payload.id; try{const saved=await request(id?API+'/'+encodeURIComponent(id):API,{method:id?'PUT':'POST',body:payload}); await uploadPhotos(saved.id); closeModal('houseFormModal'); toast('\u0110\u00e3 l\u01b0u nh\u00e0 \u1edf'); load(); if(state.current&&Number(state.current.id)===Number(saved.id))openDetail(saved.id);}catch(err){toast(err.message,'danger');}}
async function uploadPhotos(houseId){const input=$('#housePhotoFiles'); if(!input||!input.files||!input.files.length)return; const fd=new FormData(); Array.from(input.files).forEach(f=>fd.append('files[]',f)); fd.append('photo_type',$('#housePhotoTypeSelect')?.value||''); await request(API+'/'+encodeURIComponent(houseId)+'/photos',{method:'POST',body:fd}); input.value='';}
async function remove(id){if(!can('houses','delete'))return toast(labels.permission,'warning'); if(!await confirmAction({title:'Xác nhận xóa nhà ở',message:'Xóa nhà ở này?',confirmLabel:'Xóa',tone:'danger'}))return; try{await request(API+'/'+encodeURIComponent(id),{method:'DELETE'}); toast('\u0110\u00e3 x\u00f3a nh\u00e0 \u1edf'); load();}catch(e){toast(e.message,'danger');}}
async function searchHouseholds(){const input=$('#houseHouseholdAutocomplete'),host=$('#houseHouseholdSuggestions'),form=$('#houseForm'); if(!input||!host||!form)return; const q=input.value.trim(); form.elements.household_id.value=''; state.householdSuggestions=[]; if(q.length<2){hideSuggestions();return;} const data=await request(API+'/household-search?q='+encodeURIComponent(q),{cacheTtl:3000}); const items=data.items||[]; state.householdSuggestions=items; host.innerHTML=items.length?items.map(item=>'<button type="button" class="list-group-item list-group-item-action" data-platform-action="houses.selectHousehold" data-id="'+Number(item.id)+'"><div class="d-flex justify-content-between"><strong>'+esc(item.household_code)+'</strong><span class="badge text-bg-light">'+num(item.house_count)+' nh\u00e0</span></div><div>'+esc(item.head_citizen_name||'')+'</div><small class="text-muted">'+esc(item.address||'')+'</small></button>').join(''):'<div class="list-group-item text-muted">Kh\u00f4ng t\u00ecm th\u1ea5y h\u1ed9 ph\u00f9 h\u1ee3p</div>'; host.classList.remove('d-none');}
function selectHousehold(item,disabled=false){if(!item)return; const form=$('#houseForm'); form.elements.household_id.value=item.id; $('#houseHouseholdAutocomplete').value=item.household_code+' - '+(item.head_citizen_name||''); $('#houseHouseholdAutocomplete').disabled=disabled; $('#houseHouseholdSelected').textContent=item.address||''; if(!form.elements.address.value)form.elements.address.value=item.address||''; hideSuggestions();}
function hideSuggestions(){$('#houseHouseholdSuggestions')?.classList.add('d-none');}
function addStructureRow(item={}){state.structures.push(item); renderStructureRows();}
function syncStructureState(){state.structures=$$('.house-structure-row').map(row=>({structure_type:row.querySelector('[data-k="structure_type"]')?.value||'',structure_name:row.querySelector('[data-k="structure_name"]')?.value||'',area:row.querySelector('[data-k="area"]')?.value||0,build_year:row.querySelector('[data-k="build_year"]')?.value||'',condition:row.querySelector('[data-k="condition"]')?.value||'',notes:row.querySelector('[data-k="notes"]')?.value||''})).filter(s=>s.structure_type||s.structure_name); $('#houseForm').elements.structures.value=JSON.stringify(state.structures);}
function renderStructureRows(){const host=$('#houseStructureRows'); if(!host)return; const opts=(state.catalogs?.auxiliary_structure_types||state.catalogs?.structure_types||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label)+'</option>').join(''); host.innerHTML=state.structures.length?state.structures.map((s,i)=>'<div class="house-structure-row"><select data-k="structure_type" class="form-select"><option value="">Lo\u1ea1i</option>'+opts+'</select><input data-k="structure_name" class="form-control" placeholder="T\u00ean" value="'+esc(s.structure_name||'')+'"><input data-k="area" type="number" min="0" step="0.01" class="form-control" placeholder="m\u00b2" value="'+esc(s.area||'')+'"><input data-k="build_year" type="number" class="form-control" placeholder="N\u0103m" value="'+esc(s.build_year||'')+'"><input data-k="condition" class="form-control" placeholder="T\u00ecnh tr\u1ea1ng" value="'+esc(s.condition||'')+'"><input data-k="notes" class="form-control" placeholder="Ghi ch\u00fa" value="'+esc(s.notes||'')+'"><button type="button" class="btn btn-outline-danger" data-platform-action="houses.removeStructure" data-index="'+i+'"><i class="fa-solid fa-trash"></i></button></div>').join(''):'<div class="houses-empty compact">Ch\u01b0a c\u00f3 c\u00f4ng tr\u00ecnh ph\u1ee5.</div>'; $$('.house-structure-row',host).forEach((row,i)=>{row.querySelector('[data-k="structure_type"]').value=state.structures[i]?.structure_type||'';});}
function reset(){Object.assign(state,{page:1,search:'',house_type:'',condition:'',fire_risk:'',located:''}); ['housesSearch','housesTypeFilter','housesConditionFilter','housesFireRiskFilter','housesLocatedFilter'].forEach(id=>{const el=$('#'+id);if(el)el.value='';}); load();}
function exportReport(format){const endpoint=format==='pdf'?'/api/reports/export-pdf':'/api/reports/export-excel'; const q=new URLSearchParams({type:'houses'}); ['search','house_type','condition','fire_risk','located'].forEach(k=>{if(state[k])q.set(k,state[k]);}); window.open(endpoint+'?'+q.toString(),'_blank','noopener');}
function extendReports(){const select=$('#reportType'); if(!select||select.querySelector('option[value="houses"]'))return; [['houses','Danh s\u00e1ch nh\u00e0 \u1edf'],['houses-degraded','Nh\u00e0 xu\u1ed1ng c\u1ea5p'],['houses-temporary','Nh\u00e0 t\u1ea1m'],['houses-fire-risk','Nguy c\u01a1 PCCC cao'],['houses-missing-gps','Nh\u00e0 ch\u01b0a c\u00f3 GPS'],['house-structures','C\u00f4ng tr\u00ecnh ph\u1ee5']].forEach(([v,l])=>select.insertAdjacentHTML('beforeend','<option value="'+esc(v)+'">'+esc(l)+'</option>'));}
window.openHouseDetail=openDetail; window.openHouseForm=openForm; window.deleteHouse=remove;
})();
